// Calculate Risk Scores from Agent Outputs
// Consolidates analysis from Design Validation, Safety Optimization, and Predictive Maintenance agents

const items = $input.all();
const results = [];

// Get workflow configuration thresholds
const config = $('Workflow Configuration').first().json;
const criticalThreshold = config.criticalRiskThreshold || 80;
const highThreshold = config.highRiskThreshold || 60;
const mediumThreshold = config.mediumRiskThreshold || 40;

for (const item of items) {
  const json = item.json;

  // Extract risk scores from each agent's output
  const designRisk = json.designValidation?.riskScore || 0;
  const safetyRisk = json.safetyOptimization?.riskScore || 0;
  const maintenanceRisk = json.predictiveMaintenance?.riskScore || 0;

  // Calculate weighted overall risk score
  // Design: 30%, Safety: 40%, Maintenance: 30%
  const overallRiskScore = Math.round(
    (designRisk * 0.3) + 
    (safetyRisk * 0.4) + 
    (maintenanceRisk * 0.3)
  );

  // Determine risk level based on thresholds
  let riskLevel = 'low';
  if (overallRiskScore >= criticalThreshold) {
    riskLevel = 'critical';
  } else if (overallRiskScore >= highThreshold) {
    riskLevel = 'high';
  } else if (overallRiskScore >= mediumThreshold) {
    riskLevel = 'medium';
  }

  // Compile all issues from agents
  const allIssues = [
    ...(json.designValidation?.issues || []),
    ...(json.safetyOptimization?.issues || []),
    ...(json.predictiveMaintenance?.issues || [])
  ];

  // Count issues by severity
  const issueCounts = {
    critical: allIssues.filter(i => i.severity === 'critical').length,
    high: allIssues.filter(i => i.severity === 'high').length,
    medium: allIssues.filter(i => i.severity === 'medium').length,
    low: allIssues.filter(i => i.severity === 'low').length
  };

  results.push({
    json: {
      ...json,
      riskAnalysis: {
        overallRiskScore,
        riskLevel,
        componentScores: {
          design: designRisk,
          safety: safetyRisk,
          maintenance: maintenanceRisk
        },
        issueCounts,
        allIssues,
        timestamp: new Date().toISOString(),
        thresholdsUsed: {
          critical: criticalThreshold,
          high: highThreshold,
          medium: mediumThreshold
        }
      }
    }
  });
}

return results;

